const queries = [
  // === CONTRACT JOBS — company has budget, hiring AI contractors ===
  { q: 'site:linkedin.com/jobs "contract" "AI agent" OR "agentic AI" OR "automation workflow"', type: 'linkedin_jobs' },
  { q: 'site:linkedin.com/jobs "contract" "LLM" OR "RAG" OR "langchain" OR "AI engineer"', type: 'linkedin_jobs' },
  { q: 'site:linkedin.com/jobs "contract" "computer vision" OR "machine learning engineer" OR "ML engineer"', type: 'linkedin_jobs' },
  { q: 'site:linkedin.com/jobs "contract" "python" "AI" OR "automation" OR "data pipeline"', type: 'linkedin_jobs' },
  { q: 'site:linkedin.com/jobs "freelance" OR "contract" "n8n" OR "make.com" OR "workflow automation"', type: 'linkedin_jobs' },

  // === FUNDING SIGNALS — just raised money, actively building ===
  { q: 'site:linkedin.com/posts "we raised" "AI" OR "machine learning" OR "automation"', type: 'linkedin_posts' },
  { q: 'site:linkedin.com/posts "Series A" "AI" OR "automation" OR "machine learning" "building"', type: 'linkedin_posts' },
  { q: 'site:linkedin.com/posts "seed round" OR "pre-seed" "AI" OR "automation" "looking for"', type: 'linkedin_posts' },

  // === HIGH INTENT BUYER POSTS ===
  { q: 'site:linkedin.com/posts "looking for" "AI development" OR "AI agency" OR "tech partner"', type: 'linkedin_posts' },
  { q: 'site:linkedin.com/posts "need a developer" OR "need a team" "AI" OR "automation" OR "SaaS"', type: 'linkedin_posts' },
  { q: 'site:linkedin.com/posts "outsource" OR "build for us" "AI" OR "machine learning" OR "automation"', type: 'linkedin_posts' },
  { q: 'site:linkedin.com/posts "RFP" OR "vendor selection" "AI" OR "software" OR "automation"', type: 'linkedin_posts' },
  { q: 'site:linkedin.com/posts "we are building" "AI" OR "ML" "looking for" OR "hiring" OR "need"', type: 'linkedin_posts' },
];
return queries.map(q => ({ json: q }));

const skipKeywords = [
  'for hire', 'logo design', 'seo services', 'social media manager',
  'content writer', 'virtual assistant', 'data entry', 'graphic designer',
  'video editor', 'copywriter', 'i am available', 'available for hire',
  'seeking clients', 'my services'
];

const results = [];
const seenInRun = new Set();

for (const item of $input.all()) {
  const data = item.json;
  if (!data || data.error) continue;

  const organicResults = data.organic_results || [];
  const queryType = data.search_parameters?.q?.includes('linkedin.com/jobs')
    ? 'linkedin_jobs' : 'linkedin_posts';

  for (const r of organicResults) {
    if (!r.link) continue;
    if (!r.link.includes('linkedin.com')) continue;

    const isPost = r.link.includes('/posts/') || r.link.includes('/pulse/');
    const isJob  = r.link.includes('/jobs/');
    if (!isPost && !isJob) continue;

    const id = 'li_' + (r.link || '').replace(/[^a-z0-9]/gi, '').substring(0, 80);
    if (seenInRun.has(id)) continue;
    seenInRun.add(id);

    const title   = String(r.title   || '').substring(0, 500);
    const snippet = String(r.snippet || '').replace(/<[^>]*>/g, '').substring(0, 3000);
    if (!title) continue;

    const fullText = (title + ' ' + snippet).toLowerCase();
    if (skipKeywords.some(kw => fullText.includes(kw))) continue;

    let author = '';
    try {
      const urlParts = r.link.split('/');
      const inIdx = urlParts.indexOf('in');
      if (inIdx > -1) author = urlParts[inIdx + 1] || '';
      const companyIdx = urlParts.indexOf('company');
      if (companyIdx > -1) author = urlParts[companyIdx + 1] || '';
    } catch(e) {}

    results.push({ json: {
      title,
      description: snippet,
      source: queryType,
      source_url: r.link,
      source_id: id,
      posted_at: (function(){ try { const dt = r.date ? new Date(r.date) : null; return dt && !isNaN(dt.getTime()) ? dt.toISOString() : new Date().toISOString(); } catch(e) { return new Date().toISOString(); } })(),
      author: author.replace(/-/g, ' ').substring(0, 100),
      subreddit: '',
      upvotes: 0,
      num_comments: 0,
      flair_text: queryType === 'linkedin_jobs' ? 'Job/Contract' : 'Post',
      budget_text: ''
    }});
  }
}

if (results.length === 0) return [];
// Cap at 30 leads per run to avoid Gemini rate-limit timeouts
return results.slice(0, 30);

const post = $input.item.json;
const apiKey = $env.GOOGLE_AI_API_KEY;

const SYSTEM_PROMPT = `You are a senior business development analyst for ScaleBuild AI (CEO: Ujjwal Roy, ex-Intel/IBM/Micron), a custom AI/ML software development company.

ScaleBuild BUILDS: AI/ML models, computer vision, enterprise automation, SaaS products, data pipelines.

These posts are from LinkedIn — found via Google search using site:linkedin.com.

IDEAL LEAD: Someone actively looking for a tech partner, dev team, or AI implementation help.

SCORE 4 DIMENSIONS (0.0-1.0):
1. relevance_score: 0.9+=clearly seeking AI/software partner | 0.7=business pain | 0.5=vague tech need | 0.0=irrelevant
2. budget_score: 1.0=$100K+ | 0.8=$50-100K | 0.6=$25-50K | 0.5=unknown but enterprise context | 0.2=small/unclear
3. urgency_score: 1.0=this week | 0.7=1 month | 0.4=exploring | 0.2=no urgency
4. win_probability: 0.8+=explicitly seeking agency/partner | 0.5=good fit unclear | 0.3=wants freelancer | 0.1=no fit

BUDGET ESTIMATION (ALWAYS fill estimated_budget_text, never null):
- Series A/B funding post → "$50K-$200K (post-funding build)"
- Contract job posting → "$10K-$50K (contract scope)"
- Looking for tech partner/agency → "$25K-$100K (agency engagement)"
- Seed/MVP build → "$10K-$30K (MVP scope)"
- Enterprise company context → "$50K-$500K (enterprise)"
- Individual/small project → "$5K-$20K"

COMPANY EXTRACTION: Extract company name, founder name, website from LinkedIn URL or snippet. Never invent.`;

const prompt = SYSTEM_PROMPT + `

Score this LinkedIn lead. Return ONLY a single valid JSON object:
{"relevance_score":0.0,"budget_score":0.0,"urgency_score":0.0,"win_probability":0.0,"summary":"3-5 sentence detailed summary of the opportunity, pain points, and why ScaleBuild AI is a fit","industry":"FinTech/HealthTech/SaaS/General","tags":["tag1","tag2"],"reasoning":"Full detailed AI reasoning: explain each score dimension in 2-3 sentences — why this relevance score, why this budget score, why this urgency score, why this win probability. Give overall recommendation on whether to pursue and suggested approach.","estimated_budget_text":"$X-$Y (reason)","tech_stack":[],"company_name":null,"lead_founder_name":null,"lead_website":null}

Title: ${post.title}
Source: ${post.source}
Author: ${post.author || ''}
Description: ${(post.description||'').substring(0, 1000)}${post.budget_text ? '\nBudget: ' + post.budget_text : ''}`;

const body = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { maxOutputTokens: 100000, temperature: 0.2, responseMimeType: 'application/json' }
};

let s = null;
try {
  const respRaw = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + apiKey,
    body
  });
  const resp = typeof respRaw === 'string' ? JSON.parse(respRaw) : respRaw;
  const raw = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = raw.replace(/```json[\s\S]*?```|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) s = JSON.parse(match[0]);
} catch(e) {}

if (!s) s = {
  relevance_score:0.5, budget_score:0.5, urgency_score:0.3, win_probability:0.3,
  summary:'Parse error - using defaults', industry:'General', tags:[], reasoning:'Could not parse Gemini response',
  estimated_budget_text:'$10K-$50K (estimated)', tech_stack:[],
  company_name:null, lead_founder_name:null, lead_website:null
};

const overall = Math.round(((s.relevance_score*0.35)+(s.budget_score*0.30)+(s.urgency_score*0.15)+(s.win_probability*0.20))*100)/100;
const alert_tier = overall>=0.85?'instant':overall>=0.70?'digest':overall>=0.30?'dashboard':'discard';

return { json: {
  source_id: post.source_id, title: post.title, description: post.description,
  source: post.source, source_url: post.source_url, posted_at: post.posted_at,
  author: post.author, subreddit: post.subreddit || '', upvotes: post.upvotes || 0,
  num_comments: post.num_comments || 0, flair_text: post.flair_text || '',
  relevance_score: s.relevance_score, budget_score: s.budget_score,
  urgency_score: s.urgency_score, win_probability: s.win_probability,
  overall_score: overall, ai_summary: s.summary, industry: s.industry,
  ai_tags: s.tags||[], ai_reasoning: s.reasoning,
  estimated_budget_text: s.estimated_budget_text||'',
  budget_mentioned: post.budget_text || s.estimated_budget_text || '',
  tech_stack: s.tech_stack||[], company_name: s.company_name||null,
  lead_founder: s.lead_founder_name||null, lead_company: s.company_name||null,
  lead_website: s.lead_website||null, lead_contact: null,
  lead_score: Math.round(overall*10),
  alert_tier, discovered_at: new Date().toISOString(), status:'new',
  location: s.location||null, deadline_text: s.deadline_text||null,
  outreach_draft: '',
  hunter_name:'', hunter_email:'', hunter_title:'', hunter_company:''
}};

